using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        await _http.PutAsJsonAsync($"api/shipments/{id}/status", status);
    }
}

