@code {
    private List<Shipment>? _shipments;
    private string _filterText = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        _shipments?.Where(s => string.IsNullOrEmpty(_filterText)
            || s.Destination.Contains(_filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        _shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="_trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@_isLoading">
                @if (_isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (_searched && _shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@_searchedNumber</strong>.
    </div>
}

@if (_shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <strong>Tracking #: @_shipment.TrackingNumber</strong>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@_shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@_shipment.Destination</dd>
                        <dt>Shipped Date</dt>
                        <dd>@_shipment.ShippedDate.ToString("MMM dd, yyyy")</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd>
                            <span class="badge @GetStatusBadgeClass(_shipment.Status) fs-6">
                                @_shipment.Status
                            </span>
                        </dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5 fw-bold text-primary">
                            @_shipment.EstimatedDelivery.ToString("MMM dd, yyyy")
                        </dd>
                    </dl>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string _trackingNumber = string.Empty;
    private string _searchedNumber = string.Empty;
    private Shipment? _shipment;
    private bool _searched;
    private bool _isLoading;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(_trackingNumber))
            return;

        _isLoading = true;
        _searched = true;
        _searchedNumber = _trackingNumber.Trim();
        _shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(_searchedNumber);
        _isLoading = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

