using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

/// <summary>
/// Server-side in-memory implementation for demo purposes.
/// Replace with EF Core / database access in production.
/// </summary>
public class ShipmentServerService : IShipmentService
{
    private static readonly List<Shipment> _shipments = new()
    {
        new() { Id = 1, TrackingNumber = "TRK-001234", Origin = "New York, US", Destination = "London, UK", Status = ShipmentStatus.InTransit, ShippedDate = new DateTime(2026, 5, 18), EstimatedDelivery = new DateTime(2026, 5, 25), CustomerEmail = "alice@example.com" },
        new() { Id = 2, TrackingNumber = "TRK-001235", Origin = "Shanghai, CN", Destination = "Los Angeles, US", Status = ShipmentStatus.OutForDelivery, ShippedDate = new DateTime(2026, 5, 10), EstimatedDelivery = new DateTime(2026, 5, 22), CustomerEmail = "bob@example.com" },
        new() { Id = 3, TrackingNumber = "TRK-001236", Origin = "Berlin, DE", Destination = "Tokyo, JP", Status = ShipmentStatus.Pending, ShippedDate = new DateTime(2026, 5, 20), EstimatedDelivery = new DateTime(2026, 5, 30), CustomerEmail = "carol@example.com" },
        new() { Id = 4, TrackingNumber = "TRK-001237", Origin = "Sydney, AU", Destination = "Mumbai, IN", Status = ShipmentStatus.Delivered, ShippedDate = new DateTime(2026, 5, 5), EstimatedDelivery = new DateTime(2026, 5, 15), CustomerEmail = "dave@example.com" },
        new() { Id = 5, TrackingNumber = "TRK-001238", Origin = "São Paulo, BR", Destination = "Paris, FR", Status = ShipmentStatus.Delayed, ShippedDate = new DateTime(2026, 5, 12), EstimatedDelivery = new DateTime(2026, 5, 28), CustomerEmail = "eve@example.com" },
    };

    private static readonly Lock _lock = new();

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_shipments.ToList());
        }
    }

    public Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        lock (_lock)
        {
            var shipment = _shipments.FirstOrDefault(s =>
                s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
            return Task.FromResult(shipment);
        }
    }

    public Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        lock (_lock)
        {
            var shipment = _shipments.FirstOrDefault(s => s.Id == id);
            if (shipment is not null)
                shipment.Status = status;
        }
        return Task.CompletedTask;
    }
}

